class Solution {
public:
    int minMovesToMakePalindrome(string s) {
        int n = s.size();
        int moves = 0;
        int i = 0, j = n - 1;
        while (i < j) {
            if (s[i] == s[j]) {
                i++;
                j--;
            } else {
                int next = j;
                while (next > i && s[next] != s[i]) next--;
                if (next > i) {
                    moves++;
                    i++;
                    j = next;
                } else {
                    moves++;
                    j--;
                }
            }
        }
        return moves;
    }
};
